class Solution {
public:
    int maximumLengthSubstring(string s) {
        int n = s.size();
        int res = 0;
        unordered_map<char, int> count;
        int left = 0;
        for (int right = 0; right < n; right++) {
            count[s[right]]++;
            while (count.size() > 3 || count[s[right]] > 2) {
                count[s[left]]--;
                if (count[s[left]] == 0) count.erase(s[left]);
                left++;
            }
            res = max(res, right - left + 1);
        }
        return res;
    }
};
```

